// src/pages/Users.jsx
import React, { useEffect, useState } from "react";
import api from "../api";
import { useAuth } from "../AuthContext";

function Badge({ active }) {
    return (
        <span
            className={
                "inline-flex items-center px-2 py-0.5 rounded text-xs font-medium " +
                (active
                    ? "bg-emerald-50 text-emerald-700"
                    : "bg-slate-100 text-slate-600")
            }
        >
      {active ? "ACTIVE" : "INACTIVE"}
    </span>
    );
}

export default function Users() {
    const { user } = useAuth();
    const [loading, setLoading] = useState(true);
    const [rows, setRows] = useState([]);
    const [err, setErr] = useState("");

    useEffect(() => {
        let ignore = false;
        (async () => {
            setErr("");
            setLoading(true);
            try {
                const { data } = await api.get("/api/users"); // endpoint thật
                const list = Array.isArray(data?.content)
                    ? data.content
                    : Array.isArray(data)
                        ? data
                        : [];
                if (!ignore) setRows(list);
            } catch (e) {
                if (!ignore)
                    setErr(
                        e?.response?.data?.message || "Không tải được danh sách người dùng"
                    );
            } finally {
                if (!ignore) setLoading(false);
            }
        })();
        return () => {
            ignore = true;
        };
    }, []);

    return (
        <div className="p-6">
            <div className="mb-4">
                <h2 className="text-lg font-semibold">Người dùng & Phân quyền</h2>
                <p className="text-sm text-slate-500">
                    Chỉ hiển thị các trường thực có trong backend.
                </p>
            </div>

            {err && (
                <div className="mb-3 rounded-lg border border-rose-200 bg-rose-50 px-3 py-2 text-rose-700 text-sm">
                    {err}
                </div>
            )}

            <div className="overflow-hidden rounded-2xl border border-indigo-100 bg-white">
                <div className="overflow-auto">
                    <table className="min-w-full">
                        <thead className="bg-indigo-50">
                        <tr className="text-left text-slate-600">
                            <th className="px-4 py-3">Username</th>
                            <th className="px-4 py-3">Họ tên</th>
                            <th className="px-4 py-3">Email</th>
                            <th className="px-4 py-3">Vai trò</th>
                            <th className="px-4 py-3">Trạng thái</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr>
                                <td className="px-4 py-4 text-sm text-slate-500" colSpan={5}>
                                    Đang tải...
                                </td>
                            </tr>
                        ) : rows.length === 0 ? (
                            <tr>
                                <td className="px-4 py-4 text-sm text-slate-500" colSpan={5}>
                                    Chưa có dữ liệu
                                </td>
                            </tr>
                        ) : (
                            rows.map((r) => (
                                <tr key={r.id} className="hover:bg-indigo-50/40">
                                    <td className="px-4 py-3 font-medium text-slate-800">
                                        {r.username}
                                    </td>
                                    <td className="px-4 py-3">{r.fullName || "-"}</td>
                                    <td className="px-4 py-3">{r.email || "-"}</td>
                                    <td className="px-4 py-3">{r.role || "-"}</td>
                                    <td className="px-4 py-3">
                                        <Badge active={!!r.active} />
                                    </td>
                                </tr>
                            ))
                        )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}
